import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router, RouterLink } from '@angular/router';
import { MoneyPipe } from '../../core/pipes/money.pipe';
import { CartItem } from '../../core/models/storefront.models';

@Component({
  selector: 'app-checkout',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink, MoneyPipe],
  templateUrl: './checkout.component.html',
})
export class CheckoutComponent {
  form: FormGroup;
  placing = false;
  errorMessage = '';

  items = signal<CartItem[]>([
    {
      id: 'ci1',
      productId: 'p1',
      qty: 1,
      product: {
        id: 'p1',
        name: 'Aurora Wireless Headphones',
        description: '',
        priceCents: 14999,
        imageUrl: 'https://picsum.photos/seed/headphones/80/80',
        stockQty: 12,
      },
    },
    {
      id: 'ci2',
      productId: 'p2',
      qty: 2,
      product: {
        id: 'p2',
        name: 'Nimbus Mechanical Keyboard',
        description: '',
        priceCents: 9900,
        imageUrl: 'https://picsum.photos/seed/keyboard/80/80',
        stockQty: 34,
      },
    },
  ]);

  total = computed(() =>
    this.items().reduce((sum, i) => sum + i.product.priceCents * i.qty, 0),
  );

  constructor(
    private fb: FormBuilder,
    private router: Router,
  ) {
    this.form = this.fb.group({
      shipName: ['', [Validators.required, Validators.minLength(2)]],
      shipAddress: ['', [Validators.required, Validators.minLength(6)]],
    });
  }

  placeOrder(): void {
    if (this.form.invalid) return;
    this.placing = true;
    this.errorMessage = '';
    // Mockup: simulate a successful checkout and land on the orders page.
    this.router.navigate(['/orders'], { queryParams: { placed: '1' } });
  }
}
